// ── Aligned bar cell ─────────────────────────────────────────────────────────

function AlignedBarCell({
	metric,
	scores,
	colWidth,
	showThresholdLabels = false
}: Readonly<{ metric: MetricDef; scores: AuditScoreTotals | null; colWidth: number; showThresholdLabels?: boolean }>) {
	const value = scores === null ? 0 : metric.getValue(scores);
	const max = scores === null ? 0 : metric.getMax(scores);
	const isNa = scores === null || max <= 0;
	const percentage = roundedPercentOfMax(value, max);
	const fillRatio = isNa ? 0 : Math.min(1, value / max);
	const fillHeight = Math.round(fillRatio * BAR_TRACK_HEIGHT);
	const barColor = BAR_COLORS[metric.key];

	return (
		<div className="flex flex-col items-center gap-1.5 pb-1" style={{ width: colWidth }}>
			<span className={cn("text-xs font-bold tabular-nums", isNa ? "text-muted-foreground" : "text-foreground")}>
				{isNa ? "N/A" : `${percentage}%`}
			</span>
			<div
				className={cn(
					"relative flex items-end overflow-hidden rounded border",
					isNa ? "border-dashed border-border/50 bg-muted/30" : "border-border bg-muted/60"
				)}
				style={{ width: BAR_WIDTH, height: BAR_TRACK_HEIGHT }}
				role="meter"
				aria-valuenow={value}
				aria-valuemin={0}
				aria-valuemax={max}
				aria-label={`${metric.label}: ${isNa ? "not assessed" : `${percentage}%`}`}>
				{!isNa && fillHeight > 0 ? (
					<div
						className="w-full rounded-b-sm opacity-90"
						style={{ height: fillHeight, backgroundColor: barColor }}
					/>
				) : isNa ? (
					<div className="flex h-full w-full items-center justify-center text-xs text-muted-foreground/50">
						—
					</div>
				) : null}
				{/* Threshold cutoff lines — dotted, drawn across every assessed bar */}
				{!isNa
					? BAR_THRESHOLDS.map(th => (
							<div
								key={th}
								aria-hidden
								className="pointer-events-none absolute inset-x-0 border-t border-dotted border-foreground/45"
								style={{ bottom: (th / 100) * BAR_TRACK_HEIGHT }}>
								{showThresholdLabels ? (
									<span className="absolute bottom-px left-0.5 rounded-sm bg-background/75 px-0.5 text-[9px] font-semibold leading-tight tabular-nums text-muted-foreground">
										{th}%
									</span>
								) : null}
							</div>
						))
					: null}
			</div>
			<span className="text-center text-xs leading-tight text-muted-foreground">{metric.shortLabel}</span>
		</div>
	);
}

